import { Search } from "lucide-react";
import CompanyItem from "./CompanyItem";
import Header from "./Header";

const Sidebar = ({
  filteredCompanies,
  searchTerm,
  setSearchTerm,
  selectedCompany,
  handleCompanySelect,
  sidebarOpen,
  setSidebarOpen
}) => {
  return (
    <div
      className={`fixed lg:static top-0 left-0 h-full bg-white shadow-xl border-r border-gray-200 
      w-72 md:w-80 transform transition-transform duration-300 z-50
      ${sidebarOpen ? "translate-x-0" : "-translate-x-full lg:translate-x-0"}`}
    >
      {/* Close btn for mobile */}
      <div className="lg:hidden flex justify-end p-3">
        <button
          onClick={() => setSidebarOpen(false)}
          className="text-gray-600 hover:text-gray-900"
        >
          ✕
        </button>
      </div>

      <Header />

      {/* Search */}
      <div className="px-4 py-3">
        <div className="flex items-center bg-gray-100 rounded-lg px-3 py-2">
          <Search className="w-4 h-4 text-gray-500" />
          <input
            type="text"
            placeholder="Search companies..."
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
            className="bg-transparent ml-2 outline-none w-full text-sm"
          />
        </div>
      </div>

      {/* Companies list */}
      <div className="flex-1 overflow-y-auto px-2 pb-4">
        {filteredCompanies.length > 0 ? (
          filteredCompanies.map((company, idx) => (
            <CompanyItem
              key={idx}
              company={company}
              isSelected={selectedCompany?.symbol === company.symbol}
              onSelect={() => handleCompanySelect(company)}
            />
          ))
        ) : (
          <p className="text-gray-500 text-sm px-4 mt-4">No companies found.</p>
        )}
      </div>
    </div>
  );
};

export default Sidebar;
